class NativeBridge(
    private val activity: Activity,
    private val webView: WebView
) {
    private val localStorage = NativeLocalStorage(activity)
    private val pushNotifications = PushNotificationManager(activity)

    @JavascriptInterface
    fun ping(): String = "pong"

    @JavascriptInterface
    fun getDeviceInfo(): String {
        return JSONObject()
            .put("sdkInt", Build.VERSION.SDK_INT)
            .put("manufacturer", Build.MANUFACTURER)
            .put("brand", Build.BRAND)
            .put("model", Build.MODEL)
            .put("device", Build.DEVICE)
            .toString()
    }

    @JavascriptInterface
    fun setItem(key: String, value: String) {
        localStorage.setItem(key, value)
    }

    @JavascriptInterface
    fun getItem(key: String): String {
        return localStorage.getItem(key) ?: ""
    }

    @JavascriptInterface
    fun removeItem(key: String) {
        localStorage.removeItem(key)
    }

    @JavascriptInterface
    fun clearStorage() {
        localStorage.clear()
    }

    @JavascriptInterface
    fun getAllStorage(): String {
        return localStorage.getAll().toString()
    }

    @JavascriptInterface
    fun subscribePush(topic: String): String {
        return pushNotifications.subscribe(topic).toString()
    }

    @JavascriptInterface
    fun unsubscribePush(topic: String): String {
        return pushNotifications.unsubscribe(topic).toString()
    }

    @JavascriptInterface
    fun getPushToken(): String {
        return pushNotifications.getToken().toString()
    }

    @JavascriptInterface
    fun saveBase64Image(fileName: String, base64Data: String): String {
        return try {
            val cleanName = fileName.ifBlank { "image_${System.currentTimeMillis()}.png" }
            val bytes = android.util.Base64.decode(base64Data, android.util.Base64.DEFAULT)
            val dir = activity.getExternalFilesDir(Environment.DIRECTORY_PICTURES) ?: activity.filesDir
            val file = File(dir, cleanName)
            FileOutputStream(file).use { it.write(bytes) }
            JSONObject()
                .put("success", true)
                .put("path", file.absolutePath)
                .put("uri", Uri.fromFile(file).toString())
                .toString()
        } catch (e: Exception) {
            JSONObject()
                .put("success", false)
                .put("error", e.message ?: "Unknown error")
                .toString()
        }
    }

    @JavascriptInterface
    fun requestCameraAccess(callbackFunction: String) {
        activity.runOnUiThread {
            val granted = ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED
            val payload = JSONObject().put("granted", granted)
            webView.evaluateJavascript("$callbackFunction(${JSONObject.quote(payload.toString())})", null)
        }
    }

    @JavascriptInterface
    fun emitEvent(eventName: String, payloadJson: String?) {
        val safePayload = payloadJson ?: "{}"
        activity.runOnUiThread {
            webView.evaluateJavascript(
                "window.dispatchEvent(new CustomEvent(${JSONObject.quote(eventName)}, { detail: JSON.parse(${JSONObject.quote(safePayload)}) }));",
                null
            )
        }
    }

    fun notifyWeb(eventName: String, payload: JSONObject = JSONObject()) {
        activity.runOnUiThread {
            val js = "window.dispatchEvent(new CustomEvent(${JSONObject.quote(eventName)}, { detail: JSON.parse(${JSONObject.quote(payload.toString())}) }));"
            webView.evaluateJavascript(js, null)
        }
    }
}

class NativeLocalStorage(context: Context) {
    private val prefs = context.getSharedPreferences("hybrid_native_storage", Context.MODE_PRIVATE)

    fun setItem(key: String, value: String) {
        prefs.edit().putString(key, value).apply()
    }

    fun getItem(key: String): String? = prefs.getString(key, null)

    fun removeItem(key: String) {
        prefs.edit().remove(key).apply()
    }

    fun clear() {
        prefs.edit().clear().apply()
    }

    fun getAll(): JSONObject {
        val json = JSONObject()
        prefs.all.forEach { (key, value) ->
            json.put(key, value)
        }
        return json
    }
}

class PushNotificationManager(private val context: Context) {
    private val prefs = context.getSharedPreferences("hybrid_push_prefs", Context.MODE_PRIVATE)

    fun subscribe(topic: String): JSONObject {
        val topics = prefs.getStringSet("topics", emptySet())?.toMutableSet() ?: mutableSetOf()
        topics.add(topic)
        prefs.edit().putStringSet("topics", topics).apply()
        return JSONObject()
            .put("success", true)
            .put("topic", topic)
            .put("topics", JSONArray(topics))
    }

    fun unsubscribe(topic: String): JSONObject {
        val topics = prefs.getStringSet("topics", emptySet())?.toMutableSet() ?: mutableSetOf()
        topics.remove(topic)
        prefs.edit().putStringSet("topics", topics).apply()
        return JSONObject()
            .put("success", true)
            .put("topic", topic)
            .put("topics", JSONArray(topics))
    }

    fun getToken(): JSONObject {
        val token = prefs.getString("token", null) ?: "mock-token-${Build.MODEL}-${System.currentTimeMillis()}"
        prefs.edit().putString("token", token).apply()
        return JSONObject()
            .put("success", true)
            .put("token", token)
            .put("topics", JSONArray(prefs.getStringSet("topics", emptySet()) ?: emptySet()))
    }
}